import sys
from math import factorial

def main():
    n, mod = map(int, sys.stdin.readline().split())
    if n == 1:
        print(0)
        return

    # Precompute the number of inversions for all permutations of size m <= n
    inv_counts = [{} for _ in range(n+1)]
    inv_counts[1][0] = 1

    for m in range(2, n+1):
        current = {}
        prev = inv_counts[m-1]
        for inv in prev:
            cnt = prev[inv]
            for pos in range(m):
                new_inv = inv + pos
                if new_inv in current:
                    current[new_inv] += cnt
                else:
                    current[new_inv] = cnt
        inv_counts[m] = current

    total = 0
    fact = [1] * (n + 1)
    for i in range(1, n+1):
        fact[i] = fact[i-1] * i

    for m in range(1, n+1):
        current_inv = inv_counts[m]
        keys = sorted(current_inv.keys())
        prefix = [0] * (max(keys) + 2 if keys else 0)
        for inv in keys:
            prefix[inv] = current_inv[inv]
        for i in range(1, len(prefix)):
            prefix[i] += prefix[i-1]

        for inv_p in keys:
            cnt_p = current_inv[inv_p]
            max_inv_q = inv_p - 1
            if max_inv_q >= 0:
                if max_inv_q >= len(prefix) - 1:
                    sum_q = prefix[-1]
                else:
                    sum_q = prefix[max_inv_q + 1]
                total = (total + cnt_p * sum_q * fact[n] // fact[m] * fact[n - m] % mod) % mod

    print(total % mod)

if __name__ == "__main__":
    main()
